// ── Extract message from Evolution API payload ─────────────────────────────
const body = $input.item.json.body || $input.item.json;
const data = body?.data || body;
const jid = data?.key?.remoteJid || '';
const sender = jid.replace('@s.whatsapp.net','').replace('@g.us','');
const isFromMe = data?.key?.fromMe === true;
const isGroup = jid.includes('@g.us');
const msgObj = data?.message || {};
const firstKey = Object.keys(msgObj)[0] || '';

let text = '';
if (firstKey === 'conversation') text = msgObj.conversation || '';
else if (firstKey === 'extendedTextMessage') text = msgObj.extendedTextMessage?.text || '';
text = text.trim();

// ── Config ──────────────────────────────────────────────────────────────────
const BUSINESS_ACCOUNT_ID = 'd72e900f-a09e-4b8c-bf77-aff843ef754a';

// ── Ignore non-text, own messages, groups ───────────────────────────────────
if (!text || isFromMe || isGroup) {
  return [{ json: { intent: 'ignore', sender, text, itemName: '', qty: 1, BUSINESS_ACCOUNT_ID } }];
}

// ── Classify intent ─────────────────────────────────────────────────────────
// Best routing: single classification here keeps Switch node simple and testable.
const lower = text.toLowerCase();
let intent = 'buy'; // default: treat unrecognized text as item name
let itemName = text;
let qty = 1;

if (/^(hi|hello|hey|start|menu|food|list|what|show|namaste|hola|help)\b/i.test(lower)) {
  intent = 'menu'; itemName = '';

} else if (/^(status|token|my order|track|where|when will|order status)\b/i.test(lower)) {
  intent = 'status'; itemName = '';

} else if (/^(receipt|bill|invoice)\b/i.test(lower)) {
  intent = 'receipt'; itemName = '';

} else if (/^(buy|order|get|give me|i want)\s/i.test(lower)) {
  // Parse 'buy Butter Chicken 2' → itemName='Butter Chicken', qty=2
  const m = text.match(/^(?:buy|order|get|give me|i want)\s+(.+)/i);
  if (m) {
    const parts = m[1].trim().split(/\s+/);
    const last = parseInt(parts[parts.length - 1]);
    if (!isNaN(last) && last > 0 && parts.length > 1) {
      qty = last;
      itemName = parts.slice(0, -1).join(' ');
    } else {
      itemName = m[1].trim();
    }
  }
  // else: itemName stays as full text (default)
}

return [{ json: { intent, sender, text, itemName, qty, BUSINESS_ACCOUNT_ID } }];

const rows = $input.all();
if (!rows.length) return [{ json: { reply: 'Sorry, no items available right now. Check back soon!' } }];

let out = '*Mercanta Menu*\n\n';
let cat = '';
for (const r of rows) {
  const i = r.json;
  if (i.category !== cat) { cat = i.category; out += `*${cat}*\n`; }
  const tags = [];
  if (i.is_vegetarian) tags.push('🌿');
  if (i.is_spicy) tags.push('🌶');
  out += `  • ${i.item_name}${tags.length ? ' '+tags.join('') : ''} — ₹${parseFloat(i.price).toFixed(0)}\n`;
}
out += '\n_Just type an item name to order, e.g._ *Paneer Tikka*\n_Type *status* to track your order_';
return [{ json: { reply: out } }];

const rows = $input.all();
const ctx = $('Parse & Intent').item.json;

if (!rows.length || !rows[0].json.id) {
  return [{ json: {
    found: false,
    reply: `Sorry, *${ctx.itemName}* isn't available. Type *menu* to see what we have.`,
    sender: ctx.sender
  } }];
}

const item = rows[0].json;
const qty = ctx.qty || 1;
const total = parseFloat(item.price) * qty;

return [{ json: {
  found: true,
  itemId: item.id,
  itemName: item.item_name,
  price: parseFloat(item.price),
  qty,
  total,
  totalPaise: Math.round(total * 100),
  sender: ctx.sender,
  BUSINESS_ACCOUNT_ID: ctx.BUSINESS_ACCOUNT_ID
} }];

const order = $('Build Order').item.json;
const link = $('Create Payment Link').item.json;
const reply = `*Order Summary*

📦 ${order.qty}× ${order.itemName}
💰 Total: ₹${order.total.toFixed(0)}

💳 *Pay to confirm your order:*
${link.short_url}

_Your token number will be sent once payment is received._
_Type *status* to track anytime._`;
return [{ json: { reply } }];

const rows = $input.all();
if (!rows.length || !rows[0].json.token_number) {
  return [{ json: { reply: 'No active orders found. Type *menu* to browse our items.' } }];
}
const t = rows[0].json;
const statusEmoji = { ordered:'🕐', confirmed:'✅', preparing:'👨‍🍳', prepared:'🍽', ready:'🔔', served:'✅', cancelled:'❌' };
const emoji = statusEmoji[t.status] || '🕐';
let reply = `${emoji} *Token #${t.token_number}*\n\nStatus: *${t.status.toUpperCase()}*\n📦 ${t.item_name} ×${t.quantity}`;
if (t.estimated_minutes) reply += `\n⏱ Est. wait: ~${t.estimated_minutes} min`;
if (t.status === 'ready') reply += '\n\n*Your order is ready for pickup!*\nPlease collect at the counter.';
return [{ json: { reply } }];

const rows = $input.all();
if (!rows.length || !rows[0].json.date) {
  return [{ json: { reply: 'No orders found yet. Type *menu* to browse.' } }];
}
const latest = rows[0].json;
const date = new Date(latest.date).toLocaleString('en-IN', { timeZone: 'Asia/Kolkata', day:'2-digit', month:'short', hour:'2-digit', minute:'2-digit', hour12:true });
let reply = `🧾 *Last Order*\n📅 ${date}\n\n`;
for (const r of rows) {
  reply += `  • ${r.json.item_name} ×${r.json.quantity} @ ₹${parseFloat(r.json.price).toFixed(0)}\n`;
}
reply += `\n💰 *Total: ₹${parseFloat(latest.total).toFixed(0)}*`;
if (latest.token_number) reply += `\n🎫 Token: *#${latest.token_number}*`;
if (latest.order_status) reply += `\n📋 Status: ${latest.order_status}`;
return [{ json: { reply } }];
